 const XMLNS = 'http://www.w3.org/2000/svg';

+/**
+ * Sanitize an SVG string to remove potentially dangerous content.
+ * @param {string} svgString - The SVG string to sanitize.
+ * @returns {string} - The sanitized SVG string.
+ */
+const sanitizeSvgString = function (svgString) {
+    const parser = new DOMParser();
+    const doc = parser.parseFromString(svgString, 'image/svg+xml');
+
+    // Remove all script elements
+    const scripts = doc.querySelectorAll('script');
+    scripts.forEach(script => script.parentNode.removeChild(script));
+
+    // Remove dangerous attributes from all elements
+    const allElements = doc.querySelectorAll('*');
+    allElements.forEach(el => {
+        // Remove event handler attributes (on*)
+        const attrsToRemove = [];
+        for (let i = 0; i < el.attributes.length; i++) {
+            const attr = el.attributes[i];
+            if (attr.name.toLowerCase().startsWith('on')) {
+                attrsToRemove.push(attr.name);
+            }
+            // Remove javascript: URLs
+            if ((attr.name.toLowerCase() === 'href' ||
+                 attr.name.toLowerCase() === 'xlink:href' ||
+                 attr.name.toLowerCase() === 'src') &&
+                /^\s*javascript:/i.test(attr.value)) {
+                attrsToRemove.push(attr.name);
+            }
+        }
+        attrsToRemove.forEach(name => el.removeAttribute(name));
+    });
+
+    const serializer = new XMLSerializer();
+    return serializer.serializeToString(doc.documentElement);
+};
+
 /**
  * Fix SVG string so that it can be correctly parsed and displayed by the browser.
  * @param {string} svgString - String of SVG data to fix up.
