+use anyhow::{anyhow, bail, Context, Result};
+use chrono::{DateTime, Utc};
+use serde::{Deserialize, Serialize};
+use x509_cert::der::Decode as _;
+
+use crate::crypto;
+use crate::utils::*;
+
+#[derive(Debug, Deserialize, Serialize)]
+#[serde(rename_all = "camelCase")]
+pub struct QeIdentityBody {
+    pub id: String,
+    pub version: u32,
+    pub issue_date: String,
+    pub next_update: String,
+    pub tcb_evaluation_data_number: Option<u32>,
+    pub miscselect: String,
+    pub miscselect_mask: String,
+    pub attributes: String,
+    pub attributes_mask: String,
+    pub mrsigner: String,
+    pub isvprodid: u16,
+    pub tcb_levels: Vec<QeTcbLevel>,
+}
+
+#[derive(Debug, Deserialize, Serialize)]
+#[serde(rename_all = "camelCase")]
+pub struct QeTcbLevel {
+    pub tcb: QeTcb,
+    pub tcb_date: String,
+    pub tcb_status: String,
+    #[serde(default)]
+    pub advisory_ids: Vec<String>,
+}
+
+#[derive(Debug, Deserialize, Serialize)]
+pub struct QeTcb {
+    pub isvsvn: u16,
+}
+
+#[derive(Debug, Deserialize, Serialize)]
+#[serde(rename_all = "camelCase")]
+pub struct QeIdentityWrapper {
+    pub enclave_identity: QeIdentityBody,
+    pub signature: String,
+}
+
+/// Verify the QE Identity signature against the issuer certificate chain.
+pub fn verify_qe_identity_signature(
+    qe_identity_json: &str,
+    qe_identity_signature: &str,
+    qe_identity_issuer_chain: &str,
+    now: u64,
+) -> Result<()> {
+    // Parse the wrapper to get the enclave_identity portion and signature
+    let wrapper: QeIdentityWrapper = serde_json::from_str(qe_identity_json)
+        .context("Failed to parse QE Identity JSON wrapper")?;
+
+    // The signature is over the raw enclave_identity JSON value
+    // Extract the raw enclave_identity bytes from the original JSON
+    let raw_value = extract_raw_enclave_identity(qe_identity_json)
+        .context("Failed to extract raw enclave_identity from QE Identity JSON")?;
+
+    // Decode the hex signature
+    let sig_bytes = hex::decode(qe_identity_signature)
+        .context("Failed to decode QE Identity signature hex")?;
+
+    // Parse the issuer certificate chain (PEM encoded, URL-percent-encoded)
+    let chain_pem = percent_encoding::percent_decode_str(qe_identity_issuer_chain)
+        .decode_utf8()
+        .context("Failed to URL-decode QE Identity issuer chain")?;
+
+    // Parse certificates from PEM chain
+    let certs = parse_pem_chain(&chain_pem)
+        .context("Failed to parse QE Identity issuer certificate chain")?;
+
+    if certs.is_empty() {
+        bail!("QE Identity issuer certificate chain is empty");
+    }
+
+    // Verify the certificate chain validity
+    verify_certificate_chain(&certs, now)
+        .context("QE Identity issuer certificate chain validation failed")?;
+
+    // The signing certificate is the first in the chain (leaf)
+    let signing_cert = &certs[0];
+
+    // Verify the signature over the raw enclave_identity JSON
+    crypto::verify_p256_signature_der(signing_cert, raw_value.as_bytes(), &sig_bytes)
+        .context("QE Identity signature verification failed")?;
+
+    Ok(())
+}
+
+/// Check the QE Report fields against the QE Identity policy.
+/// Enforces MRSIGNER, ISVPRODID, and ISVSVN constraints.
+pub fn check_qe_report_against_identity(
+    qe_report: &[u8],
+    qe_identity_json: &str,
+) -> Result<()> {
+    let wrapper: QeIdentityWrapper = serde_json::from_str(qe_identity_json)
+        .context("Failed to parse QE Identity JSON")?;
+    let identity = &wrapper.enclave_identity;
+
+    // Parse MRSIGNER from QE Identity (hex encoded, 32 bytes)
+    let expected_mrsigner = hex::decode(&identity.mrsigner)
+        .context("Failed to decode QE Identity mrsigner")?;
+
+    // SGX Report layout (little-endian):
+    // offset 128: MRSIGNER (32 bytes)
+    // offset 256: ISVPRODID (2 bytes, little-endian)
+    // offset 258: ISVSVN (2 bytes, little-endian)
+    if qe_report.len() < 260 {
+        bail!("QE Report is too short to contain required fields");
+    }
+
+    let report_mrsigner = &qe_report[128..160];
+    let report_isvprodid = u16::from_le_bytes([qe_report[256], qe_report[257]]);
+    let report_isvsvn = u16::from_le_bytes([qe_report[258], qe_report[259]]);
+
+    // Verify MRSIGNER
+    if report_mrsigner != expected_mrsigner.as_slice() {
+        bail!(
+            "QE Report MRSIGNER mismatch: expected {}, got {}",
+            hex::encode(&expected_mrsigner),
+            hex::encode(report_mrsigner)
+        );
+    }
+
+    // Verify ISVPRODID
+    if report_isvprodid != identity.isvprodid {
+        bail!(
+            "QE Report ISVPRODID mismatch: expected {}, got {}",
+            identity.isvprodid,
+            report_isvprodid
+        );
+    }
+
+    // Verify ISVSVN: find the highest TCB level that is UpToDate and check
+    // that the report's ISVSVN meets the minimum required SVN.
+    let min_isvsvn = identity
+        .tcb_levels
+        .iter()
+        .filter(|lvl| lvl.tcb_status == "UpToDate")
+        .map(|lvl| lvl.tcb.isvsvn)
+        .min()
+        .unwrap_or(0);
+
+    if report_isvsvn < min_isvsvn {
+        bail!(
+            "QE Report ISVSVN {} is below minimum required SVN {}",
+            report_isvsvn,
+            min_isvsvn
+        );
+    }
+
+    Ok(())
+}
+
+/// Extract the raw JSON string value of the "enclaveIdentity" key from the wrapper JSON.
+fn extract_raw_enclave_identity(json: &str) -> Result<String> {
+    // Find the "enclaveIdentity" key and extract its raw JSON value
+    let key = "\"enclaveIdentity\"";
+    let start = json
+        .find(key)
+        .ok_or_else(|| anyhow!("enclaveIdentity key not found in QE Identity JSON"))?;
+    let after_key = &json[start + key.len()..];
+    let colon_pos = after_key
+        .find(':')
+        .ok_or_else(|| anyhow!("Missing colon after enclaveIdentity key"))?;
+    let after_colon = after_key[colon_pos + 1..].trim_start();
+
+    // Find the matching closing brace for the object
+    if !after_colon.starts_with('{') {
+        bail!("enclaveIdentity value is not a JSON object");
+    }
+
+    let mut depth = 0usize;
+    let mut end = 0usize;
+    let chars: Vec<char> = after_colon.chars().collect();
+    let mut in_string = false;
+    let mut escape = false;
+    for (i, &ch) in chars.iter().enumerate() {
+        if escape {
+            escape = false;
+            continue;
+        }
+        if ch == '\\' && in_string {
+            escape = true;
+            continue;
+        }
+        if ch == '"' {
+            in_string = !in_string;
+            continue;
+        }
+        if in_string {
+            continue;
+        }
+        if ch == '{' {
+            depth += 1;
+        } else if ch == '}' {
+            depth -= 1;
+            if depth == 0 {
+                end = i;
+                break;
+            }
+        }
+    }
+
+    if depth != 0 {
+        bail!("Unmatched braces in enclaveIdentity JSON value");
+    }
+
+    // Collect the raw string (byte-safe since we tracked char indices)
+    let raw: String = chars[..=end].iter().collect();
+    Ok(raw)
+}

