+static bool
+_mongoc_cmd_is_sensitive (const bson_t *cmd)
+{
+   bson_iter_t iter;
+   const char *key;
+   int i;
+
+   if (!bson_iter_init (&iter, cmd) || !bson_iter_next (&iter)) {
+      return false;
+   }
+
+   key = bson_iter_key (&iter);
+   for (i = 0; SENSITIVE_COMMANDS[i] != NULL; i++) {
+      if (strcasecmp (key, SENSITIVE_COMMANDS[i]) == 0) {
+         return true;
+      }
+   }
+
+   return false;
+}
+
+static bson_t *
+_mongoc_redact_sensitive_cmd (const bson_t *cmd)
+{
+   bson_iter_t iter;
+   bson_t *redacted;
+
+   redacted = bson_new ();
+
+   /* Only copy the first key (command name) with its value, omit the rest */
+   if (bson_iter_init (&iter, cmd) && bson_iter_next (&iter)) {
+      bson_append_iter (redacted, bson_iter_key (&iter), -1, &iter);
+   }
+
+   return redacted;
+}
